PREFIX_FEMALE = _fem_key.split("• If you recite Shacharit, Mincha, or Maariv Amidah")[0] + "• If you recite Shacharit, Mincha, or Maariv Amidah"

out = f'''"""Informal RU (ty) bodies for Rosh Chodesh seasonal explainers."""

from __future__ import annotations

_ROSH_CHODESH_SHORT = {repr(_ROSH_CHODESH_SHORT)}

_ROSH_CHODESH_GENERAL = {repr(_ROSH_CHODESH_GENERAL)}

_ROSH_CHODESH_FEMALE = {repr(_ROSH_CHODESH_FEMALE)}

ROSH_CHODESH_RU_BY_PREFIX: dict[str, str] = {{
    "Rosh Chodesh (the New Month) is the first day": _ROSH_CHODESH_SHORT,
    {repr(PREFIX_FEMALE)}: _ROSH_CHODESH_FEMALE,
    {repr(PREFIX_GENERAL)}: _ROSH_CHODESH_GENERAL,
}}


def rosh_chodesh_ru_for_key(key: str) -> str | None:
    best: str | None = None
    best_len = 0
    for prefix, val in ROSH_CHODESH_RU_BY_PREFIX.items():
        if key.startswith(prefix) and len(prefix) > best_len:
            best = val
            best_len = len(prefix)
    return best
'''

Path("_ru_rosh_chodesh_data.py").write_text(out, encoding="utf-8")
print("general", len(_ROSH_CHODESH_GENERAL), "female", len(_ROSH_CHODESH_FEMALE))
